# WARNING: Under review - generated by LLM.

from .tiny_llm_base import AgentError, ToolPolicy, Workspace


def test_task_1_creates_and_atomically_replaces_files(tmp_path):
    workspace = Workspace(ToolPolicy(tmp_path, allow_writes=True))

    assert workspace.write_file("new.txt", "one") == "wrote new.txt"
    assert (tmp_path / "new.txt").read_text(encoding="utf-8") == "one"
    assert workspace.write_file("new.txt", "two") == "wrote new.txt"
    assert (tmp_path / "new.txt").read_text(encoding="utf-8") == "two"


def test_task_1_requires_inspection_before_overwriting(tmp_path):
    (tmp_path / "existing.txt").write_text("old", encoding="utf-8")
    workspace = Workspace(ToolPolicy(tmp_path, allow_writes=True))

    try:
        workspace.write_file("existing.txt", "new")
    except AgentError as error:
        assert "must be read" in str(error)
    else:
        assert False, "expected an uninspected overwrite to be rejected"
    assert (tmp_path / "existing.txt").read_text(encoding="utf-8") == "old"


def test_task_2_edit_requires_one_exact_match(tmp_path):
    path = tmp_path / "example.py"
    path.write_text("answer = 41\n", encoding="utf-8")
    workspace = Workspace(ToolPolicy(tmp_path, allow_writes=True))
    workspace.read_file("example.py")

    workspace.edit_file("example.py", "41", "42")

    assert path.read_text(encoding="utf-8") == "answer = 42\n"
    assert workspace.modified_files == {path}


def test_task_3_commands_require_an_exact_operator_allowlist(tmp_path):
    workspace = Workspace(ToolPolicy(tmp_path))

    try:
        workspace.run_command(["some-command"])
    except AgentError as error:
        assert "not explicitly allowed" in str(error)
    else:
        assert False, "expected an unapproved command to be rejected"
